WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/39.0/connection.js")}
{!REQUIRESCRIPT("/support/console/39.0/integration.js")}

if (sforce.console.isInConsole()) {
var inConsole = 1;
} else {
var inConsole = 0;
}

if("{!JSENCODE(Case.Case_Description__c)}" == "" || "{!Case.DX_Functional_Area__c}" == "" || "{!JSENCODE(Case.DX_Resolution__c)}" ==""){
alert("The Case Description, Functional Area, and Resolution fields must all be filled out and saved before the Case can be closed.");
}
else if("{!Case.Status}" == "Closed"){
alert("This case is already closed.");
}
else{
window.top.location.href = '/apex/PromptUserForConfirmation?id={!Case.Id}&inC='+ inConsole;
}
